const row = $input.first().json;
const raw = String(row.stdout || row.data || row.output || '').trim();
let parsed;
try {
  parsed = JSON.parse(raw);
} catch (e) {
  parsed = {
    worker: 'post-push-verifier-file-reader',
    read_ok: false,
    result: 'FAIL',
    failure_reasons: ['worker_stdout_unparseable'],
    raw_preview: raw.slice(0, 300),
    test_only: true
  };
}
return [{ json: parsed }];
